#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n,m;
    if(!(cin>>n>>m)) return 0;
    vector<string> maze(n);
    for(int i=0;i<n;++i){
        cin>>maze[i];
    }
    int sr,sc,dr,dc;
    cin>>sr>>sc;
    cin>>dr>>dc;
    if(sr==dr && sc==dc){
        cout<<0<<"\n";
        return 0;
    }
    vector<vector<char>> visited(n, vector<char>(m,0));
    queue<array<int,3>> q;
    q.push({sr,sc,0});
    visited[sr][sc]=1;
    const int dirs[4][2]={{1,0},{-1,0},{0,1},{0,-1}};
    while(!q.empty()){
        auto cur=q.front();q.pop();
        int r=cur[0],c=cur[1],d=cur[2];
        int nd=d+1;
        for(auto &dir:dirs){
            int nr=r+dir[0];
            int nc=c+dir[1];
            if(nr>=0 && nr<n && nc>=0 && nc<m && !visited[nr][nc] && maze[nr][nc]=='0'){
                if(nr==dr && nc==dc){
                    cout<<nd<<"\n";
                    return 0;
                }
                visited[nr][nc]=1;
                q.push({nr,nc,nd});
            }
        }
    }
    cout<<-1<<"\n";
    return 0;
}
